+use std::ffi::{c_char, c_int, c_void};
+
+unsafe fn malloc_unterminated(bytes: &[u8]) -> *mut c_char {
+    let ptr = unsafe { malloc(bytes.len()).cast::<c_char>() };
+    assert!(!ptr.is_null());
+    unsafe { std::ptr::copy_nonoverlapping(bytes.as_ptr(), ptr.cast::<u8>(), bytes.len()) };
+    ptr
+}

